const MO = ["Janvier","Février","Mars","Avril","Mai","Juin","Juillet","Août","Sept.","Octobre","Nov.","Déc."];

const FLAGS = {"France":"🇫🇷","Belgique":"🇧🇪","Allemagne":"🇩🇪","Espagne":"🇪🇸","Royaume-Uni":"🇬🇧","Pays-Bas":"🇳🇱","Italie":"🇮🇹","Portugal":"🇵🇹","Slovaquie":"🇸🇰","Pologne":"🇵🇱","Luxembourg":"🇱🇺","Autriche":"🇦🇹","Hongrie":"🇭🇺","République Tchèque":"🇨🇿","Suisse":"🇨🇭"};

// ============ CALCULATION LOGIC ============
// Energy composite: répartition fixe Élec 5% / Gasoil 70% / Gaz 25%
function calcEnergyRate(elec, gasoil, gaz) {
  return Math.round(((5*elec + 70*gasoil + 25*gaz) / 100) * 100) / 100;
}

function calcFR({dept, pal, prem, tgt, rdv, adr, month, elec, gasoil, gaz, surete}) {
  if (!FR_T[dept] || pal <= 0) return null;
  let idx = -1, mp = null;
  for (let i = 0; i < FR_P.length; i++) { if (pal <= FR_P[i]) { idx = i; mp = FR_P[i]; break; } }
  if (idx === -1) return { err: "Maximum 6 palettes" };
  const b = FR_T[dept][idx]; if (!b) return { err: "Tarif indisponible" };
  const ff=2.05, pc=prem?Math.max(b*0.30,30):0, tc=tgt?Math.min(Math.max(b*0.15,25),40):0, rc=rdv?5:0;
  // ADR is 15%, calculated below after subtotal
  const dC=dept.substring(0,2), isSeas=SEAS.includes(dC), inSeas=month>=4&&month<=8;
  const sc=(isSeas&&inSeas)?Math.round(b*0.15*100)/100:0;
  // Energy applies on PORT ONLY (base tariff b), NOT on subtotal
  const energyRate = calcEnergyRate(elec, gasoil, gaz);
  const ec = Math.round(b * (energyRate / 100) * 100) / 100;
  // Frais de facturation systématiques
  const factu = 5.00;
  // Sûreté optionnelle
  const sc2 = surete ? 0.70 : 0;
  // Sous-total avant ADR = port + frais fixes + options + saison
  const subBeforeAdr = b + ff + pc + tc + rc + sc;
  // ADR = 15% du montant de l'expédition (sous-total)
  const ac = adr ? Math.round(subBeforeAdr * 0.15 * 100) / 100 : 0;
  const sub = subBeforeAdr + ac;
  // Total HT = sous-total + énergie (sur port) + facturation + sûreté
  const totHT = Math.round((sub + ec + factu + sc2) * 100) / 100;
  // TVA 20% pour France
  const tva = Math.round(totHT * 0.20 * 100) / 100;
  const totTTC = Math.round((totHT + tva) * 100) / 100;
  return { b,ff,pc,tc,rc,ac,sc,ec,energyRate,factu,sc2,sub,totHT,tva,totTTC,isSeas,inSeas,mp };
}

function findIntl(country, zone, kg) {
  // Try IP first (PDF extracted full zones), then IX (Excel zones)
  let data = IP[country]?.[zone] || IX[country]?.[zone];
  if (!data) return null;
  for (let i = 0; i < IW.length; i++) {
    if (kg >= IW[i][0] && kg <= IW[i][1]) {
      if (data[i] === null) return { err: "Zone non desservie" };
      return { price: data[i], bracket: IW[i][0] + "–" + IW[i][1] + " kg", idx: i, all: data };
    }
  }
  return { err: "Poids hors limites (max 3000 kg)" };
}

// Get all zones for a country (merge IP + IX)
function getZones(country) {
  const ipZones = IP[country] ? Object.keys(IP[country]) : [];
  const ixZones = IX[country] ? Object.keys(IX[country]) : [];
  const all = [...new Set([...ipZones, ...ixZones])];
  all.sort();
  return all;
}

// Auto-detect French department from postal code
function detectFrDept(postalCode, allDepts) {
  const pc = postalCode.replace(/\s+/g, '');
  if (pc.length < 2) return null;
  // Extract first 2 digits
  const d2 = pc.substring(0, 2);
  // Special case: 20 = Corse
  if (d2 === '20') return allDepts.find(d => d.startsWith('20')) || null;
  // Match department starting with those 2 digits
  return allDepts.find(d => d.startsWith(d2)) || null;
}

// Country code prefixes for zone matching
const ZONE_PREFIX = {
  "Portugal":"PT","Slovaquie":"SK","Pologne":"PL","Luxembourg":"LU",
  "Autriche":"AT","Hongrie":"HU","République Tchèque":"CZ","Suisse":"CH",
  "Belgique":"BE-","Allemagne":"DE-","Espagne":"ES-","Pays-Bas":"NL-","Italie":"IT-",
  "Royaume-Uni":"GB"
};

// Auto-detect zone from postal code
function detectZone(country, postalCode, allZones) {
  if (!country || !postalCode || !allZones.length) return null;
  const pc = postalCode.replace(/\s+/g, '').toUpperCase();
  const prefix = ZONE_PREFIX[country];
  if (!prefix) return null;

  // Luxembourg = single zone
  if (country === "Luxembourg") return allZones.includes("LU") ? "LU" : null;

  // UK: extract alpha prefix from postcode (e.g. "SW1A 1AA" → "SW", "AB10 1QR" → "AB", "B1 1BB" → "B")
  if (country === "Royaume-Uni") {
    const ukMatch = pc.match(/^([A-Z]{1,2})/);
    if (!ukMatch) return null;
    const area = "GB" + ukMatch[1];
    return allZones.find(z => z === area) || null;
  }

  // All others: extract first 2 digits from postal code
  const digitMatch = pc.match(/(\d{2})/);
  if (!digitMatch) return null;
  const digits = digitMatch[1];

  // IX countries (PT, SK, PL, AT, HU, CZ, CH): zone = PREFIX + digits (e.g. PT38)
  if (!prefix.includes("-")) {
    const candidate = prefix + digits;
    return allZones.find(z => z === candidate) || null;
  }

  // IP countries (BE-, DE-, ES-, NL-, IT-): zone = PREFIX + digits + " City" — match start
  const searchPrefix = prefix + digits;
  return allZones.find(z => z.startsWith(searchPrefix)) || null;
}

function getCountries() {
  const all = [...new Set([...Object.keys(IP), ...Object.keys(IX)])];
  all.sort((a,b) => a.localeCompare(b, 'fr'));
  return all;
}

// ============ STYLES ============
const css = `
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800;900&family=JetBrains+Mono:wght@400;500;600;700&display=swap');
*{margin:0;padding:0;box-sizing:border-box;}

/* ====== LIGHT THEME — Champagne & Gold Luxe ====== */
[data-theme="light"]{
  --bg:#faf8f4;--bgGrad:linear-gradient(175deg,#faf8f4 0%,#f0ebe2 100%);
  --surface:#ffffff;--surfaceHover:#f7f4ef;--surfaceGlass:rgba(255,255,255,0.85);
  --border:#e2ddd4;--borderLight:#ece7de;
  --text:#1a1610;--textSoft:#3d3529;--textMuted:#8a7f6e;--textDim:#b5aa98;
  --accent:#b8860b;--accentLight:#d4a017;--accentDark:#946b08;
  --accentGlow:rgba(184,134,11,0.12);--accentGlow2:rgba(184,134,11,0.06);
  --accent2:#7c5e3c;--accent2Glow:rgba(124,94,60,0.1);
  --emerald:#1a8a5c;--emeraldGlow:rgba(26,138,92,0.1);
  --amber:#c07d10;--amberGlow:rgba(192,125,16,0.08);
  --blue:#2563a0;--blueGlow:rgba(37,99,160,0.08);
  --cardShadow:0 2px 16px rgba(26,22,16,0.06),0 1px 3px rgba(26,22,16,0.04);
  --cardGlowShadow:0 0 0 1px var(--accent),0 4px 24px var(--accentGlow),0 1px 3px rgba(26,22,16,0.06);
  --headerGrad:linear-gradient(180deg,rgba(184,134,11,0.06) 0%,transparent 100%);
  --priceGrad:linear-gradient(135deg,#b8860b,#d4a017);
  --toggleBg:#e8e0d4;--toggleActive:var(--accent);
  --btnActive:var(--accent);--btnActiveShadow:0 4px 16px var(--accentGlow);
  --dropBg:#ffffff;--dropBorder:#e2ddd4;--dropShadow:0 12px 40px rgba(26,22,16,0.12);
  --dropHover:#f7f4ef;--dropActiveBg:rgba(184,134,11,0.08);--dropActiveText:var(--accent);--dropActiveBorder:var(--accent);
  --inputBg:#faf8f4;--inputBorder:#e2ddd4;--inputFocusBorder:var(--accent);--inputFocusGlow:0 0 0 3px var(--accentGlow);
  --radius:16px;--radiusSm:10px;--radiusXs:6px;
}

/* ====== DARK THEME — Multicolor Neon Luxe ====== */
[data-theme="dark"]{
  --bg:#08070a;--bgGrad:linear-gradient(175deg,#08070a 0%,#0f0d14 50%,#0a0c12 100%);
  --surface:#14121a;--surfaceHover:#1e1b26;--surfaceGlass:rgba(20,18,26,0.85);
  --border:#2a2635;--borderLight:#38334a;
  --text:#f0eef5;--textSoft:#c8c4d4;--textMuted:#8e88a0;--textDim:#5e5875;
  --accent:#a855f7;--accentLight:#c084fc;--accentDark:#7c3aed;
  --accentGlow:rgba(168,85,247,0.2);--accentGlow2:rgba(168,85,247,0.08);
  --accent2:#ec4899;--accent2Glow:rgba(236,72,153,0.15);
  --emerald:#34d399;--emeraldGlow:rgba(52,211,153,0.12);
  --amber:#fbbf24;--amberGlow:rgba(251,191,36,0.1);
  --blue:#60a5fa;--blueGlow:rgba(96,165,250,0.12);
  --cardShadow:0 4px 24px rgba(0,0,0,0.4),0 1px 3px rgba(0,0,0,0.3);
  --cardGlowShadow:0 0 30px var(--accentGlow),0 0 60px rgba(236,72,153,0.08),0 8px 32px rgba(0,0,0,0.4);
  --headerGrad:linear-gradient(180deg,rgba(168,85,247,0.08) 0%,rgba(236,72,153,0.04) 50%,transparent 100%);
  --priceGrad:linear-gradient(135deg,#a855f7,#ec4899,#f97316);
  --toggleBg:#2a2635;--toggleActive:linear-gradient(135deg,#a855f7,#ec4899);
  --btnActive:linear-gradient(135deg,#a855f7,#ec4899);--btnActiveShadow:0 4px 20px var(--accentGlow),0 4px 20px var(--accent2Glow);
  --dropBg:#14121a;--dropBorder:#2a2635;--dropShadow:0 20px 60px rgba(0,0,0,0.7);
  --dropHover:#1e1b26;--dropActiveBg:rgba(168,85,247,0.15);--dropActiveText:#c084fc;--dropActiveBorder:#a855f7;
  --inputBg:#0f0d14;--inputBorder:#2a2635;--inputFocusBorder:#a855f7;--inputFocusGlow:0 0 0 3px var(--accentGlow);
  --radius:16px;--radiusSm:10px;--radiusXs:6px;
}

body{color:var(--text);font-family:'Outfit',sans-serif;-webkit-font-smoothing:antialiased;}
::selection{background:var(--accentGlow);color:var(--accent);}
::-webkit-scrollbar{width:5px;}
::-webkit-scrollbar-track{background:transparent;}
::-webkit-scrollbar-thumb{background:var(--border);border-radius:10px;}
input[type=number]::-webkit-inner-spin-button{opacity:1;}
@keyframes fadeUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
@keyframes slideIn{from{opacity:0;transform:translateX(-8px)}to{opacity:1;transform:translateX(0)}}
@keyframes countUp{from{opacity:0;transform:scale(0.8)}to{opacity:1;transform:scale(1)}}
@keyframes shimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}
@keyframes orbFloat{0%,100%{transform:translate(0,0) scale(1)}33%{transform:translate(30px,-20px) scale(1.1)}66%{transform:translate(-20px,15px) scale(0.95)}}
`;

// ============ UI COMPONENTS ============
function GlassCard({ children, style, glow, delay = 0 }) {
  return (
    <div style={{
      background: 'var(--surfaceGlass)',
      backdropFilter: 'blur(20px)',
      borderRadius: 'var(--radius)',
      padding: 24,
      border: glow ? '1px solid var(--accent)' : '1px solid var(--border)',
      boxShadow: glow ? 'var(--cardGlowShadow)' : 'var(--cardShadow)',
      animation: `fadeUp 0.5s ease ${delay}s both`,
      transition: 'all 0.4s ease',
      overflow: 'visible',
      ...style
    }}>
      {children}
    </div>
  );
}

function Tag({ children, color = 'accent' }) {
  const colors = {
    accent: { bg: 'var(--accentGlow)', text: 'var(--accent)', border: 'var(--accent)' },
    emerald: { bg: 'var(--emeraldGlow)', text: 'var(--emerald)', border: 'var(--emerald)' },
    amber: { bg: 'var(--amberGlow)', text: 'var(--amber)', border: 'var(--amber)' },
    blue: { bg: 'var(--blueGlow)', text: 'var(--blue)', border: 'var(--blue)' },
  };
  const c = colors[color] || colors.accent;
  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', padding: '3px 10px',
      borderRadius: 20, background: c.bg, color: c.text, fontSize: 11, fontWeight: 600,
      border: `1px solid ${c.border}`, letterSpacing: 0.5, opacity: 0.9 }}>
      {children}
    </span>
  );
}

function SearchSelect({ options, value, onChange, placeholder, icon }) {
  const [open, setOpen] = useState(false);
  const [search, setSearch] = useState("");
  const listRef = useRef(null);

  const filtered = useMemo(() => {
    if (!search) return options;
    const q = search.toLowerCase().replace(/[àâä]/g,"a").replace(/[éèêë]/g,"e").replace(/[ïî]/g,"i").replace(/[ôö]/g,"o").replace(/[ùûü]/g,"u").replace(/ç/g,"c");
    return options.filter(o => {
      const n = o.toLowerCase().replace(/[àâä]/g,"a").replace(/[éèêë]/g,"e").replace(/[ïî]/g,"i").replace(/[ôö]/g,"o").replace(/[ùûü]/g,"u").replace(/ç/g,"c");
      return n.includes(q);
    });
  }, [options, search]);

  const handleSelect = useCallback((opt) => {
    onChange(opt);
    setOpen(false);
    setSearch("");
  }, [onChange]);

  return (
    <div>
      <div
        onClick={() => { setOpen(!open); setSearch(""); }}
        style={{
          display: "flex", alignItems: "center", gap: 10,
          padding: "12px 16px", background: "var(--inputBg)",
          border: open ? "1.5px solid var(--accent)" : "1.5px solid var(--border)",
          borderRadius: 10, cursor: "pointer",
          boxShadow: open ? "var(--inputFocusGlow)" : "none",
          transition: "all 0.2s",
        }}
      >
        {icon && <span style={{ fontSize: 18 }}>{icon}</span>}
        <span style={{
          flex: 1, fontSize: 14,
          color: value ? "var(--text)" : "var(--textDim)",
          fontWeight: value ? 500 : 400,
          overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap",
        }}>
          {value || placeholder}
        </span>
        <span style={{
          fontSize: 10, color: "var(--textDim)",
          transform: open ? "rotate(180deg)" : "none",
          transition: "transform 0.25s", display: "inline-block",
        }}>&#9660;</span>
      </div>

      {open && (
        <div style={{
          marginTop: 6, background: "var(--dropBg)", border: "1px solid var(--dropBorder)",
          borderRadius: 10, overflow: "hidden",
          boxShadow: "var(--dropShadow)",
        }}>
          <div style={{ padding: 8, borderBottom: "1px solid var(--border)" }}>
            <input
              autoFocus
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder={"Rechercher parmi " + options.length + "..."}
              style={{
                width: "100%", padding: "10px 14px",
                background: "var(--inputBg)", border: "1px solid var(--border)",
                borderRadius: 6, color: "var(--text)", fontSize: 14,
                outline: "none", fontFamily: "Outfit, sans-serif",
              }}
            />
          </div>
          <div ref={listRef} style={{ maxHeight: 240, overflowY: "auto" }}>
            {filtered.length === 0 ? (
              <div style={{ padding: 20, textAlign: "center", color: "var(--textDim)", fontSize: 13 }}>
                Aucun résultat
              </div>
            ) : (
              filtered.slice(0, 80).map((opt) => (
                <div
                  key={opt}
                  onClick={() => handleSelect(opt)}
                  style={{
                    padding: "10px 16px", cursor: "pointer", fontSize: 13,
                    background: opt === value ? "var(--dropActiveBg)" : "transparent",
                    color: opt === value ? "var(--dropActiveText)" : "var(--textSoft)",
                    fontWeight: opt === value ? 600 : 400,
                    borderLeft: opt === value ? "3px solid var(--dropActiveBorder)" : "3px solid transparent",
                    borderBottom: "1px solid var(--borderLight)",
                    transition: "background 0.15s",
                  }}
                  onMouseEnter={e => { if (opt !== value) e.target.style.background = "var(--dropHover)"; }}
                  onMouseLeave={e => { if (opt !== value) e.target.style.background = "transparent"; }}
                >
                  {opt}
                </div>
              ))
            )}
            {filtered.length > 80 && (
              <div style={{ padding: 10, textAlign: "center", color: "var(--textDim)", fontSize: 11 }}>
                +{filtered.length - 80} — tapez pour affiner
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

function NumInput({ value, onChange, label, suffix, min = 0, max, step = 1 }) {
  return (
    <div>
      <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: 2.5,
        color: 'var(--textDim)', marginBottom: 8 }}>{label}</div>
      <div style={{ display: 'flex', alignItems: 'center', gap: 0, background: 'var(--inputBg)',
        border: '1.5px solid var(--border)', borderRadius: 'var(--radiusSm)', overflow: 'hidden',
        transition: 'all 0.2s' }}>
        <input type="number" value={value} onChange={e => onChange(Number(e.target.value))}
          min={min} max={max} step={step}
          style={{
            flex: 1, padding: '12px 16px', background: 'transparent', border: 'none',
            color: 'var(--text)', fontSize: 16, fontFamily: 'JetBrains Mono', fontWeight: 600,
            outline: 'none', width: '100%',
          }} />
        {suffix && <span style={{ padding: '12px 14px', color: 'var(--textDim)', fontSize: 12,
          fontWeight: 600, borderLeft: '1px solid var(--border)', background: 'var(--bg)' }}>{suffix}</span>}
      </div>
    </div>
  );
}

function Toggle({ on, onChange, label, desc }) {
  return (
    <div onClick={onChange} style={{
      display: 'flex', alignItems: 'center', gap: 14, cursor: 'pointer',
      padding: '12px 16px', borderRadius: 'var(--radiusSm)',
      background: on ? 'var(--accentGlow)' : 'transparent',
      border: `1.5px solid ${on ? 'var(--accent)' : 'var(--border)'}`,
      transition: 'all 0.25s',
    }}>
      <div style={{ width: 40, height: 22, borderRadius: 11,
        background: on ? 'var(--accent)' : 'var(--toggleBg)',
        position: 'relative', transition: 'all 0.3s', flexShrink: 0 }}>
        <div style={{ width: 18, height: 18, borderRadius: 9, background: 'white',
          position: 'absolute', top: 2, left: on ? 20 : 2, transition: 'all 0.3s',
          boxShadow: '0 2px 6px rgba(0,0,0,0.2)' }} />
      </div>
      <div>
        <div style={{ fontSize: 13, color: on ? 'var(--accent)' : 'var(--textSoft)', fontWeight: on ? 600 : 400, transition: 'all 0.2s' }}>{label}</div>
        {desc && <div style={{ fontSize: 11, color: 'var(--textDim)', marginTop: 2 }}>{desc}</div>}
      </div>
    </div>
  );
}

function PriceDisplay({ amount, label, sub }) {
  if (!amount && amount !== 0) return null;
  return (
    <div style={{ textAlign: 'center', animation: 'countUp 0.4s ease both' }}>
      {label && <div style={{ fontSize: 11, fontWeight: 600, textTransform: 'uppercase',
        letterSpacing: 2, color: 'var(--textDim)', marginBottom: 8 }}>{label}</div>}
      <div style={{ fontFamily: 'JetBrains Mono', fontWeight: 700, fontSize: 44,
        background: 'var(--priceGrad)', backgroundSize: '200% auto',
        WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
        animation: 'shimmer 4s linear infinite',
        lineHeight: 1, letterSpacing: -1 }}>
        {amount.toFixed(2)}
        <span style={{ fontSize: 20, fontWeight: 500 }}> €</span>
      </div>
      {sub && <div style={{ fontSize: 12, color: 'var(--textDim)', marginTop: 6 }}>{sub}</div>}
    </div>
  );
}

function ResultLine({ label, value, accent, bold }) {
  return (
    <div style={{
      display: 'flex', justifyContent: 'space-between', alignItems: 'center',
      padding: '8px 0', borderBottom: '1px solid var(--borderLight)',
      animation: 'slideIn 0.3s ease both',
    }}>
      <span style={{ fontSize: 13, color: 'var(--textMuted)', fontWeight: bold ? 600 : 400 }}>{label}</span>
      <span style={{
        fontFamily: 'JetBrains Mono', fontSize: 14, fontWeight: bold ? 700 : 500,
        color: accent ? 'var(--accent)' : value === '0.00 €' ? 'var(--textDim)' : 'var(--text)',
      }}>{value}</span>
    </div>
  );
}

// ============ MAIN APP ============
export default function XPOCalculator() {
  const [mode, setMode] = useState('france');
  const [theme, setTheme] = useState('light');
  const isDark = theme === 'dark';
  // France state
  const [dept, setDept] = useState('');
  const [pal, setPal] = useState(1);
  const [prem, setPrem] = useState(false);
  const [tgt, setTgt] = useState(false);
  const [rdv, setRdv] = useState(false);
  const [adr, setAdr] = useState(false);
  const [month, setMonth] = useState(new Date().getMonth());
  const [surete, setSurete] = useState(false);
  // Energy composite — 3 components
  const [elec, setElec] = useState(1.76);
  const [gasoilRate, setGasoilRate] = useState(6.39);
  const [gazRate, setGazRate] = useState(11.95);
  // International state
  const [country, setCountry] = useState('');
  const [zone, setZone] = useState('');
  const [postalCode, setPostalCode] = useState('');
  const [weight, setWeight] = useState(200);
  // International energy (same 3 components shared)
  const [elecIntl, setElecIntl] = useState(1.76);
  const [gasoilIntl, setGasoilIntl] = useState(6.39);
  const [gazIntl, setGazIntl] = useState(11.95);
  const [sureteIntl, setSureteIntl] = useState(false);
  const [adrIntl, setAdrIntl] = useState(false);

  const [frPostal, setFrPostal] = useState('');

  const depts = useMemo(() => Object.keys(FR_T).sort(), []);
  const countries = useMemo(() => getCountries(), []);
  const zones = useMemo(() => country ? getZones(country) : [], [country]);

  const frResult = useMemo(() => {
    if (mode !== 'france' || !dept) return null;
    return calcFR({ dept, pal, prem, tgt, rdv, adr, month, elec, gasoil: gasoilRate, gaz: gazRate, surete });
  }, [mode, dept, pal, prem, tgt, rdv, adr, month, elec, gasoilRate, gazRate, surete]);

  const intlResult = useMemo(() => {
    if (mode !== 'international' || !country || !zone || weight <= 0) return null;
    return findIntl(country, zone, weight);
  }, [mode, country, zone, weight]);

  const totalZones = useMemo(() => {
    let n = 0;
    countries.forEach(c => { n += getZones(c).length; });
    return n;
  }, [countries]);

  return (
    <div data-theme={theme} style={{ minHeight: '100vh', background: 'var(--bg)', transition: 'background 0.5s ease' }}>
      <style>{css}</style>
      
      {/* DECORATIVE ORBS (dark mode only) */}
      {isDark && (
        <>
          <div style={{ position: 'fixed', top: -120, right: -120, width: 350, height: 350,
            borderRadius: '50%', background: 'radial-gradient(circle, rgba(168,85,247,0.08), transparent 70%)',
            animation: 'orbFloat 20s ease-in-out infinite', pointerEvents: 'none', zIndex: 0 }} />
          <div style={{ position: 'fixed', bottom: -80, left: -80, width: 280, height: 280,
            borderRadius: '50%', background: 'radial-gradient(circle, rgba(236,72,153,0.06), transparent 70%)',
            animation: 'orbFloat 25s ease-in-out infinite reverse', pointerEvents: 'none', zIndex: 0 }} />
        </>
      )}

      {/* HEADER */}
      <div style={{
        background: 'var(--headerGrad)',
        borderBottom: '1px solid var(--border)',
        padding: '20px 20px 20px',
        position: 'relative', zIndex: 1,
      }}>
        <div style={{ maxWidth: 520, margin: '0 auto' }}>
          {/* Top row: Logo + Theme Toggle */}
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
              <div style={{
                width: 38, height: 38, borderRadius: 10,
                background: isDark ? 'linear-gradient(135deg, #a855f7, #ec4899)' : 'linear-gradient(135deg, #b8860b, #d4a017)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 18, fontWeight: 900, color: 'white',
                boxShadow: isDark ? '0 4px 20px rgba(168,85,247,0.3)' : '0 4px 20px rgba(184,134,11,0.2)',
                transition: 'all 0.5s',
              }}>X</div>
              <div>
                <div style={{ fontSize: 20, fontWeight: 800, letterSpacing: -0.5, color: 'var(--text)' }}>XPO Logistics</div>
                <div style={{ fontSize: 10, color: 'var(--textDim)', letterSpacing: 1.5, fontWeight: 500 }}>
                  {Object.keys(FR_T).length} depts + {totalZones} zones
                </div>
              </div>
            </div>

            {/* THEME TOGGLE — Sun/Moon */}
            <div
              onClick={() => setTheme(isDark ? 'light' : 'dark')}
              style={{
                width: 56, height: 30, borderRadius: 15, cursor: 'pointer',
                background: isDark
                  ? 'linear-gradient(135deg, #1e1b4b, #312e81)'
                  : 'linear-gradient(135deg, #fef3c7, #fde68a)',
                border: isDark ? '1px solid #4338ca' : '1px solid #d4a017',
                position: 'relative', transition: 'all 0.4s ease',
                boxShadow: isDark
                  ? '0 0 12px rgba(99,102,241,0.3), inset 0 1px 3px rgba(0,0,0,0.3)'
                  : '0 0 12px rgba(251,191,36,0.2), inset 0 1px 3px rgba(0,0,0,0.05)',
                overflow: 'hidden',
              }}
            >
              {/* Stars (dark) */}
              {isDark && <>
                <div style={{ position: 'absolute', top: 6, left: 8, width: 2, height: 2, borderRadius: '50%', background: '#e0e7ff', opacity: 0.8, transition: 'opacity 0.4s' }} />
                <div style={{ position: 'absolute', top: 14, left: 14, width: 1.5, height: 1.5, borderRadius: '50%', background: '#c7d2fe', opacity: 0.6 }} />
                <div style={{ position: 'absolute', top: 8, left: 20, width: 1, height: 1, borderRadius: '50%', background: '#e0e7ff', opacity: 0.5 }} />
              </>}
              {/* Knob */}
              <div style={{
                width: 24, height: 24, borderRadius: 12,
                position: 'absolute', top: 3,
                left: isDark ? 29 : 3,
                background: isDark
                  ? 'linear-gradient(135deg, #c7d2fe, #e0e7ff)'
                  : 'linear-gradient(135deg, #f97316, #fbbf24)',
                transition: 'all 0.4s cubic-bezier(0.68, -0.15, 0.32, 1.15)',
                boxShadow: isDark
                  ? '0 0 8px rgba(199,210,254,0.5), inset 2px -2px 0 #818cf8'
                  : '0 0 10px rgba(251,191,36,0.6)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 13,
              }}>
                {isDark ? '🌙' : '☀️'}
              </div>
            </div>
          </div>

          {/* MODE SWITCH */}
          <div style={{
            display: 'flex', gap: 4, padding: 4, background: 'var(--surface)',
            borderRadius: 'var(--radiusSm)', border: '1px solid var(--border)',
          }}>
            {[['france', '🇫🇷 France'], ['international', '🌍 International']].map(([m, label]) => (
              <button key={m} onClick={() => { setMode(m); }}
                style={{
                  flex: 1, padding: '10px 16px', borderRadius: 'var(--radiusXs)',
                  border: 'none', cursor: 'pointer', fontSize: 13, fontWeight: 600,
                  fontFamily: 'Outfit',
                  background: mode === m ? (isDark ? 'linear-gradient(135deg, #a855f7, #ec4899)' : 'var(--accent)') : 'transparent',
                  color: mode === m ? 'white' : 'var(--textMuted)',
                  transition: 'all 0.3s',
                  boxShadow: mode === m ? 'var(--btnActiveShadow)' : 'none',
                }}>{label}</button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 520, margin: '0 auto', padding: '20px 16px 40px' }}>
        
        {/* ===== FRANCE MODE ===== */}
        {mode === 'france' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <GlassCard delay={0}>
              <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 12 }}>
                📮 Code postal → Détection automatique
              </div>
              <div style={{ display: 'flex', gap: 10, alignItems: 'flex-end' }}>
                <div style={{ flex: 1 }}>
                  <input
                    value={frPostal}
                    onChange={e => {
                      const val = e.target.value;
                      setFrPostal(val);
                      const detected = detectFrDept(val, depts);
                      if (detected) setDept(detected);
                    }}
                    placeholder="Ex: 13100, 75008, 69001..."
                    style={{
                      width: '100%', padding: '12px 16px',
                      background: 'var(--inputBg)', border: '1.5px solid var(--border)',
                      borderRadius: 10, color: 'var(--text)', fontSize: 15,
                      fontFamily: 'JetBrains Mono', fontWeight: 600,
                      outline: 'none', letterSpacing: 2,
                    }}
                    onFocus={e => { e.target.style.borderColor = 'var(--accent)'; e.target.style.boxShadow = 'var(--inputFocusGlow)'; }}
                    onBlur={e => { e.target.style.borderColor = 'var(--border)'; e.target.style.boxShadow = 'none'; }}
                  />
                </div>
                {dept && frPostal && (
                  <div style={{
                    padding: '10px 14px', borderRadius: 10,
                    background: 'var(--emeraldGlow)', border: '1px solid var(--emerald)',
                    fontFamily: 'JetBrains Mono', fontSize: 12, fontWeight: 700,
                    color: 'var(--emerald)', whiteSpace: 'nowrap',
                    animation: 'countUp 0.3s ease both',
                  }}>
                    ✓ {dept.substring(0, 5)}
                  </div>
                )}
              </div>

              <div style={{ marginTop: 12, fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 8 }}>
                📍 Département {dept ? '(détecté)' : '— sélection manuelle'}
              </div>
              <SearchSelect options={depts} value={dept} onChange={setDept}
                placeholder="Sélectionner un département" icon="📍" />
            </GlassCard>

            <GlassCard delay={0.05}>
              <NumInput label="Palettes" value={pal} onChange={setPal} suffix="pal" min={0.5} max={6} step={0.5} />
            </GlassCard>

            <GlassCard delay={0.07}>
              <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 12 }}>
                ⚡ Indices énergie
              </div>
              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 10 }}>
                <NumInput label="Élec" value={elec} onChange={setElec} suffix="%" min={0} max={50} step={0.01} />
                <NumInput label="Gasoil" value={gasoilRate} onChange={setGasoilRate} suffix="%" min={0} max={50} step={0.01} />
                <NumInput label="Gaz" value={gazRate} onChange={setGazRate} suffix="%" min={0} max={50} step={0.01} />
              </div>
              <div style={{ marginTop: 10, padding: '8px 12px', borderRadius: 'var(--radiusXs)',
                background: 'var(--accentGlow)', border: '1px solid var(--accent)', textAlign: 'center' }}>
                <span style={{ fontSize: 10, color: 'var(--textDim)' }}>Répartition 5%/70%/25% → Taux composite : </span>
                <span style={{ fontFamily: 'JetBrains Mono', fontSize: 13, fontWeight: 700, color: 'var(--accent)' }}>
                  {calcEnergyRate(elec, gasoilRate, gazRate).toFixed(2)}%
                </span>
                <span style={{ fontSize: 10, color: 'var(--textDim)' }}> (sur port uniquement)</span>
              </div>
            </GlassCard>

            <GlassCard delay={0.1}>
              <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 12 }}>
                ⚙️ Options
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
                <Toggle on={prem} onChange={() => setPrem(!prem)} label="Premium" desc="+ 30% (min 30€)" />
                <Toggle on={tgt} onChange={() => setTgt(!tgt)} label="TGT Express" desc="+ 15% (25-40€)" />
                <Toggle on={rdv} onChange={() => setRdv(!rdv)} label="Rendez-vous" desc="+ 5.00€" />
                <Toggle on={adr} onChange={() => setAdr(!adr)} label="ADR Matières dangereuses" desc="+ 15% du montant" />
                <Toggle on={surete} onChange={() => setSurete(!surete)} label="Contribution sûreté" desc="+ 0.70€ / expédition" />
              </div>
            </GlassCard>

            <GlassCard delay={0.15}>
              <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 10 }}>
                📅 Mois de livraison
              </div>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4 }}>
                {MO.map((m, i) => (
                  <button key={i} onClick={() => setMonth(i)}
                    style={{
                      padding: '6px 10px', borderRadius: 'var(--radiusXs)', border: 'none',
                      cursor: 'pointer', fontSize: 11, fontWeight: month === i ? 700 : 400,
                      fontFamily: 'Outfit',
                      background: month === i ? 'var(--accent)' : 'var(--surface)',
                      color: month === i ? 'white' : 'var(--textDim)',
                      transition: 'all 0.2s',
                    }}>{m}</button>
                ))}
              </div>
            </GlassCard>

            {/* FRANCE RESULT */}
            {frResult && !frResult.err && (
              <GlassCard glow delay={0.2}>
                <PriceDisplay amount={frResult.totTTC} label="Total TTC" sub={`${frResult.mp} palette${frResult.mp > 1 ? 's' : ''} max`} />
                <div style={{ marginTop: 20 }}>
                  <ResultLine label="Port (base tarifaire)" value={frResult.b.toFixed(2) + ' €'} />
                  <ResultLine label="Frais fixes" value={frResult.ff.toFixed(2) + ' €'} />
                  {frResult.pc > 0 && <ResultLine label="Premium" value={frResult.pc.toFixed(2) + ' €'} />}
                  {frResult.tc > 0 && <ResultLine label="TGT Express" value={frResult.tc.toFixed(2) + ' €'} />}
                  {frResult.rc > 0 && <ResultLine label="Rendez-vous" value={frResult.rc.toFixed(2) + ' €'} />}
                  {frResult.ac > 0 && <ResultLine label="⚠️ ADR Matières dangereuses (15%)" value={frResult.ac.toFixed(2) + ' €'} accent />}
                  {frResult.sc > 0 && <ResultLine label="🌊 Surtaxe saisonnière" value={frResult.sc.toFixed(2) + ' €'} accent />}
                  <ResultLine label={`Énergie (${frResult.energyRate.toFixed(2)}% sur port)`} value={frResult.ec.toFixed(2) + ' €'} />
                  <ResultLine label="Frais de facturation" value={frResult.factu.toFixed(2) + ' €'} />
                  {frResult.sc2 > 0 && <ResultLine label="Contribution sûreté" value={frResult.sc2.toFixed(2) + ' €'} />}
                  <div style={{ margin: '12px 0 6px', padding: '10px 0', borderTop: '2px solid var(--border)' }}>
                    <ResultLine label="Total HT" value={frResult.totHT.toFixed(2) + ' €'} bold />
                    <ResultLine label="TVA (20%)" value={frResult.tva.toFixed(2) + ' €'} />
                    <ResultLine label="TOTAL TTC" value={frResult.totTTC.toFixed(2) + ' €'} accent bold />
                  </div>
                </div>
                {frResult.isSeas && (
                  <div style={{ marginTop: 12, padding: '8px 12px', borderRadius: 'var(--radiusXs)',
                    background: frResult.inSeas ? 'var(--amberGlow)' : 'var(--emeraldGlow)',
                    border: `1px solid ${frResult.inSeas ? 'var(--amber)' : 'var(--emerald)'}`,
                    fontSize: 11, color: frResult.inSeas ? 'var(--amber)' : 'var(--emerald)' }}>
                    {frResult.inSeas ? '⚠️ Zone saisonnière active (Mai–Août) → +15%' : 'ℹ️ Zone saisonnière — inactive en ce moment'}
                  </div>
                )}
              </GlassCard>
            )}
            {frResult?.err && (
              <GlassCard><div style={{ textAlign: 'center', color: 'var(--amber)', fontSize: 14 }}>{frResult.err}</div></GlassCard>
            )}
          </div>
        )}

        {/* ===== INTERNATIONAL MODE ===== */}
        {mode === 'international' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            <GlassCard delay={0}>
              <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 12 }}>
                🌍 Pays de destination
              </div>
              <SearchSelect
                options={countries.map(c => `${FLAGS[c] || '🏳️'} ${c}`)}
                value={country ? `${FLAGS[country] || '🏳️'} ${country}` : ''}
                onChange={v => { const name = v.replace(/^[^\s]+ /, ''); setCountry(name); setZone(''); setPostalCode(''); }}
                placeholder="Sélectionner un pays" icon="🌐"
              />
              {country && (
                <div style={{ marginTop: 8 }}>
                  <Tag color="blue">{zones.length} zones disponibles</Tag>
                </div>
              )}
            </GlassCard>

            {country && (
              <GlassCard delay={0.05}>
                <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                  letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 12 }}>
                  📮 Code postal → Détection automatique
                </div>
                <div style={{ display: 'flex', gap: 10, alignItems: 'flex-end' }}>
                  <div style={{ flex: 1 }}>
                    <input
                      value={postalCode}
                      onChange={e => {
                        const val = e.target.value;
                        setPostalCode(val);
                        const detected = detectZone(country, val, zones);
                        if (detected) setZone(detected);
                      }}
                      placeholder={country === 'Royaume-Uni' ? 'Ex: SW1A 1AA' : 'Ex: 3885-401'}
                      style={{
                        width: '100%', padding: '12px 16px',
                        background: 'var(--inputBg)', border: '1.5px solid var(--border)',
                        borderRadius: 10, color: 'var(--text)', fontSize: 15,
                        fontFamily: 'JetBrains Mono', fontWeight: 600,
                        outline: 'none', letterSpacing: 1,
                      }}
                      onFocus={e => { e.target.style.borderColor = 'var(--accent)'; e.target.style.boxShadow = 'var(--inputFocusGlow)'; }}
                      onBlur={e => { e.target.style.borderColor = 'var(--border)'; e.target.style.boxShadow = 'none'; }}
                    />
                  </div>
                  {zone && postalCode && (
                    <div style={{
                      padding: '10px 16px', borderRadius: 10,
                      background: 'var(--emeraldGlow)', border: '1px solid var(--emerald)',
                      fontFamily: 'JetBrains Mono', fontSize: 14, fontWeight: 700,
                      color: 'var(--emerald)', whiteSpace: 'nowrap',
                      animation: 'countUp 0.3s ease both',
                    }}>
                      ✓ {zone}
                    </div>
                  )}
                </div>
                {postalCode && !zone && (
                  <div style={{ marginTop: 8, padding: '6px 12px', borderRadius: 'var(--radiusXs)',
                    background: 'var(--amberGlow)', border: '1px solid var(--amber)',
                    fontSize: 11, color: 'var(--amber)' }}>
                    Zone non trouvée — sélectionnez manuellement ci-dessous
                  </div>
                )}

                <div style={{ marginTop: 12, fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                  letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 8 }}>
                  📍 Zone {zone ? '(détectée)' : '/ Ville — sélection manuelle'}
                </div>
                <SearchSelect options={zones} value={zone} onChange={setZone}
                  placeholder="Sélectionner une zone" icon="🎯" />
              </GlassCard>
            )}

            {country && (
              <GlassCard delay={0.1}>
              <NumInput label="Poids marchandise" value={weight} onChange={setWeight} suffix="kg" min={1} max={3000} step={10} />
                <div style={{ marginTop: 10, display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                  {[200, 500, 800, 1000, 1500, 2000, 2500].map(w => (
                    <button key={w} onClick={() => setWeight(w)}
                      style={{
                        padding: '4px 10px', borderRadius: 20, border: 'none', cursor: 'pointer',
                        fontSize: 11, fontFamily: 'JetBrains Mono', fontWeight: weight === w ? 700 : 400,
                        background: weight === w ? 'var(--accent)' : 'var(--surface)',
                        color: weight === w ? 'white' : 'var(--textDim)',
                        transition: 'all 0.2s',
                      }}>{w} kg</button>
                  ))}
                </div>
              </GlassCard>
            )}

            {country && (
              <GlassCard delay={0.12}>
                <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                  letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 12 }}>
                  ⚡ Indices énergie
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 10 }}>
                  <NumInput label="Élec" value={elecIntl} onChange={setElecIntl} suffix="%" min={0} max={50} step={0.01} />
                  <NumInput label="Gasoil" value={gasoilIntl} onChange={setGasoilIntl} suffix="%" min={0} max={50} step={0.01} />
                  <NumInput label="Gaz" value={gazIntl} onChange={setGazIntl} suffix="%" min={0} max={50} step={0.01} />
                </div>
                <div style={{ marginTop: 10, padding: '8px 12px', borderRadius: 'var(--radiusXs)',
                  background: 'var(--accentGlow)', border: '1px solid var(--accent)', textAlign: 'center' }}>
                  <span style={{ fontSize: 10, color: 'var(--textDim)' }}>Taux composite : </span>
                  <span style={{ fontFamily: 'JetBrains Mono', fontSize: 13, fontWeight: 700, color: 'var(--accent)' }}>
                    {calcEnergyRate(elecIntl, gasoilIntl, gazIntl).toFixed(2)}%
                  </span>
                </div>
                <div style={{ marginTop: 10, display: 'flex', flexDirection: 'column', gap: 6 }}>
                  <Toggle on={adrIntl} onChange={() => setAdrIntl(!adrIntl)} label="ADR Matières dangereuses" desc="+ 15% du montant" />
                  <Toggle on={sureteIntl} onChange={() => setSureteIntl(!sureteIntl)} label="Contribution sûreté" desc="+ 0.70€ / expédition" />
                </div>
              </GlassCard>
            )}

            {/* INTERNATIONAL RESULT */}
            {intlResult && !intlResult.err && (() => {
              const basePrice = intlResult.price;
              const intlEnergyRate = calcEnergyRate(elecIntl, gasoilIntl, gazIntl);
              const ecIntl = Math.round(basePrice * intlEnergyRate / 100 * 100) / 100;
              const factuIntl = 5.00;
              const sc2Intl = sureteIntl ? 0.70 : 0;
              const acIntl = adrIntl ? Math.round(basePrice * 0.15 * 100) / 100 : 0;
              const totalHT = Math.round((basePrice + ecIntl + factuIntl + sc2Intl + acIntl) * 100) / 100;
              // International = TVA exonérée (intracommunautaire ou export)
              return (
              <GlassCard glow delay={0.15}>
                <PriceDisplay amount={totalHT} label="Total HT" sub={intlResult.bracket} />
                <div style={{ marginTop: 16 }}>
                  <ResultLine label="Prix transport grille" value={basePrice.toFixed(2) + ' €'} />
                  <ResultLine label={`Énergie (${intlEnergyRate.toFixed(2)}% sur port)`} value={ecIntl.toFixed(2) + ' €'} />
                  <ResultLine label="Frais de facturation" value={factuIntl.toFixed(2) + ' €'} />
                  {acIntl > 0 && <ResultLine label="⚠️ ADR Matières dangereuses (15%)" value={acIntl.toFixed(2) + ' €'} accent />}
                  {sc2Intl > 0 && <ResultLine label="Contribution sûreté" value={sc2Intl.toFixed(2) + ' €'} />}
                  <div style={{ margin: '12px 0 6px', padding: '10px 0', borderTop: '2px solid var(--border)' }}>
                    <ResultLine label="TOTAL HT" value={totalHT.toFixed(2) + ' €'} accent bold />
                  </div>
                  <div style={{ padding: '8px 12px', borderRadius: 'var(--radiusXs)',
                    background: 'var(--blueGlow)', border: '1px solid var(--blue)',
                    fontSize: 11, color: 'var(--blue)', textAlign: 'center' }}>
                    Exonéré de TVA — Livraison {['Royaume-Uni','Suisse'].includes(country) ? 'export hors UE' : 'intracommunautaire'}
                  </div>
                </div>
                {intlResult.all && (
                  <div style={{ marginTop: 20 }}>
                    <div style={{ fontSize: 10, fontWeight: 700, textTransform: 'uppercase',
                      letterSpacing: 2.5, color: 'var(--textDim)', marginBottom: 10 }}>
                      Grille complète — {zone}
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 4 }}>
                      {IW.map((bracket, i) => {
                        const p = intlResult.all[i];
                        const isActive = i === intlResult.idx;
                        return (
                          <div key={i} style={{
                            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
                            padding: '6px 10px', borderRadius: 'var(--radiusXs)',
                            background: isActive ? 'var(--accentGlow)' : 'transparent',
                            border: isActive ? '1px solid var(--accent)' : '1px solid transparent',
                          }}>
                            <span style={{ fontSize: 10, color: isActive ? 'var(--accent)' : 'var(--textDim)', fontWeight: isActive ? 600 : 400 }}>
                              {bracket[0]}–{bracket[1]}kg
                            </span>
                            <span style={{
                              fontFamily: 'JetBrains Mono', fontSize: 11, fontWeight: isActive ? 700 : 500,
                              color: isActive ? 'var(--accent)' : p ? 'var(--textSoft)' : 'var(--textDim)',
                            }}>
                              {p ? p.toFixed(0) + '€' : '—'}
                            </span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </GlassCard>
              );
            })()}
            {intlResult?.err && (
              <GlassCard><div style={{ textAlign: 'center', color: 'var(--amber)', fontSize: 14 }}>{intlResult.err}</div></GlassCard>
            )}
          </div>
        )}
      </div>

      {/* FOOTER */}
      <div style={{
        textAlign: 'center', padding: '16px 20px', borderTop: '1px solid var(--border)',
        fontSize: 11, color: 'var(--textDim)', position: 'relative', zIndex: 1,
      }}>
        XPO Connect Europe — Grilles Janvier 2025 — {Object.keys(FR_T).length + totalZones} zones
      </div>
    </div>
  );
}
